+                    __pi_end_extension();
+
+                    __pi_begin_extension("ext.emitter", { name: "ext.emitter" });
+                    pi.events("emit", { name: "named_event", data: { via: "name_field" } })
+                      .then((r) => { globalThis.emitResult = r; });
