+            .state
+            .create_task(root, Budget::INFINITE, async move {
+                let mut s = s2.lock().expect("lock");
+                s.enqueue_event("alpha".into(), serde_json::json!("a"));
+                s.enqueue_event("beta".into(), serde_json::json!("b"));
